import{_ as a,o as t,c as r,a3 as o}from"./chunks/framework.oxq6d-og.js";const u=JSON.parse('{"title":"Why NThread?","description":"","frontmatter":{},"headers":[],"relativePath":"en/nthread/overview.md","filePath":"en/nthread/overview.md"}'),n={name:"en/nthread/overview.md"};function d(s,e,c,i,l,h){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="why-nthread" tabindex="-1">Why NThread? <a class="header-anchor" href="#why-nthread" aria-label="Permalink to &quot;Why NThread?&quot;">​</a></h1><p><code>NThread</code> temporarily redirects one existing OS thread in a target process instead of creating a remote thread. This avoids <code>CreateRemoteThread</code>; it does not mean no target allocation can occur, because middleware and stack-argument handling can allocate working memory or small stubs.</p><p>For normal application code, use <code>createAccessor(pid)</code>. It races candidate threads, selects the first successful redirection, and returns the complete accessor chain. Direct <code>NThread</code> construction is an advanced path that makes lifecycle ownership your responsibility.</p><p>NThread can run calls on a live target thread, read their result from context, and restore saved general-purpose, control, and XMM state during deinitialization. It cannot guarantee that a selected thread is safe to suspend, that it is not holding a lock, or that a call will return.</p>',4)])])}const m=a(n,[["render",d]]);export{u as __pageData,m as default};
